  `end_date` date NOT NULL COMMENT '账单结束日期 - 最后一期账单结束时间',
  `cooling_off_start_time` datetime DEFAULT NULL COMMENT '冷静期开始时间（放款成功时间）',
  `cooling_off_end_time` datetime DEFAULT NULL COMMENT '冷静期结束时间（放款成功时间 + 24 小时）',
  `fee_cap_amount` decimal(18,2) DEFAULT NULL COMMENT '费用上限金额（等于本金）',
  `state` int(11) NOT NULL COMMENT '借据状态',
  `accumulated_fee_amount` decimal(18,2) NOT NULL DEFAULT '0.00' COMMENT '累计费用金额，汇总已还和应还：利息+服务费+逾期费累计',
  `total_overdue_fee` decimal(18,2) NOT NULL DEFAULT '0.00' COMMENT '总逾期费，汇总所有账单逾期费',
  `repay_coupon_amount` decimal(18,2) NOT NULL DEFAULT '0.00' COMMENT '还款优惠券金额，汇总子账单还款优惠金额',
  `paid_principal` decimal(18,2) NOT NULL DEFAULT '0.00' COMMENT '已还本金，汇总所有账单已还本金',
  `paid_interest` decimal(18,2) NOT NULL DEFAULT '0.00' COMMENT '已还利息，汇总所有账单已还利息',
  `paid_service_fee` decimal(18,2) NOT NULL DEFAULT '0.00' COMMENT '已还服务费，汇总所有账单已还服务费',
  `paid_overdue_fee` decimal(18,2) NOT NULL DEFAULT '0.00' COMMENT '已还逾期费，汇总所有账单已还逾期费',
  `paid_amount` decimal(18,2) NOT NULL DEFAULT '0.00' COMMENT '已还金额，汇总所有账单已还总金额',
  `remaining_principal` decimal(18,2) NOT NULL COMMENT '剩余应还本金',
  `remaining_interest` decimal(18,2) NOT NULL COMMENT '剩余应还利息',
  `remaining_service_fee` decimal(18,2) NOT NULL COMMENT '剩余应还服务费',
  `remaining_overdue_fee` decimal(18,2) NOT NULL COMMENT '剩余应还逾期费',
  `remaining_amount` decimal(18,2) NOT NULL COMMENT '剩余应还金额',
  `payment_account_id` bigint(20) DEFAULT NULL COMMENT '收款账户id',
  `fee_capped` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否达到费用上限，0否，1是',
  `fee_capped_time` datetime DEFAULT NULL COMMENT '达到费用上限时间，达到封顶时间',
  `settled_type` varchar(32) NOT NULL DEFAULT 'NONE' COMMENT '结清类型，NONE：未结清，NORMAL：正常结清，COOLING_OFF：冷静期结清，EARLY：提前结清',
  `settled_time` datetime DEFAULT NULL COMMENT '结清时间',
  `is_del` bigint(20) NOT NULL DEFAULT '0' COMMENT '是否删除, 0:否，其他：删除时间戳',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
