  `voucher_no` varchar(64) NOT NULL COMMENT '借款订单号',
  `user_id` bigint(20) NOT NULL COMMENT '客户ID',
  `product_id` bigint(20) NOT NULL COMMENT '产品ID',
  `channel_pay_no` varchar(64) DEFAULT NULL COMMENT '渠道支付号',
  `payable_amount` decimal(18,2) DEFAULT NULL COMMENT '应还总金额',
  `difference_amount` decimal(18,2) DEFAULT NULL COMMENT '差额金额',
  `coupon_no` varchar(32) DEFAULT NULL COMMENT '使用的优惠券编号',
  `coupon_amount` decimal(18,2) DEFAULT NULL COMMENT '优惠券抵扣金额',
  `repay_start_time` datetime DEFAULT NULL COMMENT '还款发起时间',
  `repay_success_time` datetime DEFAULT NULL COMMENT '还款成功时间',
  `repay_type` varchar(32) DEFAULT NULL COMMENT '还款类型',
  `repay_amount` decimal(18,2) DEFAULT NULL COMMENT '还款金额, 客户实际支付金额',
  `pay_channel` varchar(32) DEFAULT NULL COMMENT '支付渠道, Easypaisa/JazzCash/Bank/Manual',
  `pay_txn_no` varchar(128) DEFAULT NULL COMMENT '支付流水号, 三方支付流水号',
  `wallet_type` varchar(32) DEFAULT NULL COMMENT '付款钱包类型, Easypaisa/JazzCash/Bank',
  `wallet_real_name` varchar(64) DEFAULT NULL COMMENT '付款人姓名',
  `wallet_account` varchar(64) DEFAULT NULL COMMENT '付款账户号',
  `pay_state` int(11) DEFAULT NULL COMMENT '支付状态',
  `match_state` int(11) DEFAULT NULL COMMENT '匹配状态',
  `reconcile_state` int(11) DEFAULT NULL COMMENT '对账状态',
  `fail_reason` varchar(255) DEFAULT NULL COMMENT '支付失败原因',
  `reconciled_time` datetime DEFAULT NULL COMMENT '对账完成时间',
  `expire_time` datetime DEFAULT NULL COMMENT '到期时间',
  `is_del` bigint(20) NOT NULL DEFAULT '0' COMMENT '是否删除, 0:否，其他：删除时间戳',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `modify_time` datetime DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `idx_repayment_order_no` (`repayment_no`) USING BTREE,
  KEY `idx_repayment_order_voucher_no` (`voucher_no`) USING BTREE,
  KEY `idx_repayment_order_channel_pay_no` (`channel_pay_no`) USING BTREE,
  KEY `idx_repayment_order_user_id` (`user_id`,`create_time`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='还款订单表';;

CREATE TABLE `loan_voucher_bill` (
  `id` bigint(20) NOT NULL COMMENT '主键',
  `bill_no` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '账单号，普通分期账单号',
  `voucher_no` varchar(64) NOT NULL COMMENT '借款订单号，关联借款订单',
  `user_id` bigint(20) NOT NULL COMMENT '客户ID',
  `product_id` bigint(20) NOT NULL COMMENT '产品ID - 产品ID',
  `term_seq` int(11) DEFAULT NULL COMMENT '期数 - 第 1/2/3 期',
  `term` int(11) DEFAULT NULL COMMENT '总期数 - 总分期期数',
  `start_date` date DEFAULT NULL COMMENT '账单开始日 - 本期计息开始日',
  `end_date` date DEFAULT NULL COMMENT '账单到期日',
  `repay_date` date DEFAULT NULL COMMENT '本期还款日',
  `period_days` int(11) DEFAULT NULL COMMENT '账单天数 - 例如 15 天',
  `state` int(11) DEFAULT NULL COMMENT '账单状态',
  `payable_principal` decimal(18,2) DEFAULT NULL COMMENT '应还本金，本期应还本金',
  `payable_interest_amount` decimal(18,2) DEFAULT NULL COMMENT '应还利息',
  `payable_service_fee` decimal(18,2) DEFAULT NULL COMMENT '应还服务费',
  `payable_overdue_fee` decimal(18,2) DEFAULT NULL COMMENT '应还逾期费',
  `payable_amount` decimal(18,2) DEFAULT NULL COMMENT '当前应还金额，优惠后本期应还本金+应还利息+应还服务费+应还逾期费',
  `paid_principal` decimal(18,2) DEFAULT NULL COMMENT '已还本金 - 本期已还本金',
  `paid_interest` decimal(18,2) DEFAULT NULL COMMENT '已还利息 - 本期已还利息',
  `paid_service_fee` decimal(18,2) DEFAULT NULL COMMENT '已还服务费',
  `paid_overdue_fee` decimal(18,2) DEFAULT NULL COMMENT '已还逾期费',
  `paid_amount` decimal(18,2) DEFAULT NULL COMMENT '本期已还总金额',
  `remaining_principal` decimal(18,2) DEFAULT NULL COMMENT '剩余本金 - 本期剩余本金',
  `remaining_interest` decimal(18,2) DEFAULT NULL COMMENT '剩余利息 - 本期剩余利息',
  `remaining_service_fee` decimal(18,2) DEFAULT NULL COMMENT '剩余服务费 - 本期剩余服务费',
  `remaining_overdue_fee` decimal(18,2) DEFAULT NULL COMMENT '剩余逾期费 - 本期剩余逾期费',
  `remaining_amount` decimal(18,2) DEFAULT NULL COMMENT '剩余应还金额 - 本期剩余应还',
  `overdue_days` int(11) NOT NULL DEFAULT '0' COMMENT '逾期天数 - 当前逾期天数',
  `is_overdue` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否逾期 - 0否，1是',
  `settled_type` varchar(32) NOT NULL DEFAULT 'NONE' COMMENT '结清类型，NONE：未结清，NORMAL：正常结清，COOLING_OFF：冷静期结清，EARLY：提前结清，CURRENT_EARLY',
  `settled_time` datetime DEFAULT NULL COMMENT '结清时间 - 普通账单被关闭时间',
  `settlement_record_no` varchar(255) DEFAULT NULL COMMENT '提前结清记录号',
  `settlement_bill_no` varchar(255) DEFAULT NULL COMMENT '结清账单号 - 普通账单被提前结清关闭时，关联这笔提前结清账单',
  `batching_time` datetime DEFAULT NULL COMMENT '最后一次跑批时间 - 跑批时间',
  `is_del` bigint(20) NOT NULL DEFAULT '0' COMMENT '是否删除, 0:否，其他：删除时间戳',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `modify_time` datetime DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `idx_voucher_bill_no` (`bill_no`) USING BTREE,
  KEY `idx_voucher_bill_voucher_no` (`voucher_no`) USING BTREE,
  KEY `idx_voucher_bill_user_id` (`user_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='还款计划表';;

CREATE TABLE `loan_coupon_template` (
  `id` bigint(20) NOT NULL COMMENT '主键ID - 自增ID',
  `coupon_name` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '优惠券名称',
  `coupon_type` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '优惠券类型',
  `coupon_amount` decimal(18,2) NOT NULL DEFAULT '0.00' COMMENT '优惠券金额',
  `product_id` bigint(20) DEFAULT NULL COMMENT '适用产品ID',
  `effect_time` datetime DEFAULT NULL COMMENT '生效开始时间',
  `expire_time` datetime DEFAULT NULL COMMENT '过期时间',
  `issued_count` int(11) NOT NULL DEFAULT '0' COMMENT '已发放数量',
  `rule_config` json DEFAULT NULL COMMENT '券规则',
  `is_del` bigint(20) NOT NULL DEFAULT '0' COMMENT '删除标识 - 0:未删除 1:已删除',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `modify_time` datetime DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='优惠券模板';;

CREATE TABLE `loan_credit_quota` (
  `id` bigint(20) NOT NULL COMMENT 'id,对应授信记录id',
  `user_id` bigint(20) NOT NULL COMMENT '用户id',
  `total_credit` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '总授信额',
  `used_credit` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '已用额度（已借出尚未还清）',
  `locked_credit` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '冻结额度（放款中等被冻结）',
  `approved_time` datetime DEFAULT NULL COMMENT '授信通过时间',
  `is_del` bigint(20) NOT NULL DEFAULT '0' COMMENT '是否删除，0:否，其他：删除时间戳',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `modify_time` datetime DEFAULT NULL COMMENT '最近修改时间',
  PRIMARY KEY (`id`),
  KEY `idx_credit_apply_user_id` (`user_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='授信额度';;

CREATE TABLE `loan_bill_fee_changelog` (
  `id` bigint(20) NOT NULL COMMENT '主键',
  `voucher_no` varchar(64) NOT NULL COMMENT '借款订单号',
  `bill_no` varchar(64) NOT NULL COMMENT '账单号',
  `user_id` bigint(20) NOT NULL COMMENT '客户ID',
  `product_id` bigint(20) NOT NULL COMMENT '产品ID - 贷款产品ID',
  `term_seq` int(11) DEFAULT NULL COMMENT '当前期数',
  `fee_type` varchar(32) DEFAULT NULL COMMENT '费用类型 - Principal/Interest/ServiceFee/OverdueFee/coupon',
  `change_type` varchar(32) DEFAULT NULL COMMENT '变更类型 - Create/Increase/Decrease/Waive/Pay/Refund/Reverse',
  `source_type` varchar(32) DEFAULT NULL COMMENT '触发来源 - System/Repayment/Coupon/Manual/Overdue/EarlySettlement/Reconciliation',
  `source_no` varchar(64) DEFAULT NULL COMMENT '来源单号 - 还款单号、优惠券使用记录号、调整单号、提前结清单号等',
  `change_amount` decimal(18,2) DEFAULT NULL COMMENT '变更金额',
  `before_payable_amount` decimal(18,2) DEFAULT NULL COMMENT '变更前应收金额',
  `after_payable_amount` decimal(18,2) DEFAULT NULL COMMENT '变更后应收金额',
  `before_paid_amount` decimal(18,2) DEFAULT NULL COMMENT '变更前已收金额',
  `paid_change_amount` decimal(18,2) DEFAULT NULL COMMENT '本次入账金额',
  `after_paid_amount` decimal(18,2) DEFAULT NULL COMMENT '变更后已收金额 - 变更后已收金额',
  `before_remaining_amount` decimal(18,2) DEFAULT NULL COMMENT '变更前剩余金额',
  `after_remaining_amount` decimal(18,2) DEFAULT NULL COMMENT '变更后剩余金额',
  `waived_change_amount` decimal(18,2) DEFAULT NULL COMMENT '减免金额 - 本次减免金额',
  `change_reason` varchar(255) DEFAULT NULL COMMENT '变更原因 - 变更原因',
  `operator_id` bigint(20) DEFAULT NULL COMMENT '操作人ID - 系统操作可为空或填系统用户',
  `remark` varchar(255) DEFAULT NULL COMMENT '备注 - 备注',
  `is_del` bigint(20) NOT NULL DEFAULT '0' COMMENT '是否删除, 0:否，其他：删除时间戳',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `modify_time` datetime DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`),
  KEY `idx_bill_fee_changelog_voucher_no` (`voucher_no`) USING BTREE,
  KEY `idx_bill_fee_changelog_bill_no` (`bill_no`) USING BTREE,
  KEY `idx_bill_fee_changelog_user_id` (`user_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='账单费用变更记录表';;

CREATE TABLE `loan_product` (
  `id` bigint(20) NOT NULL COMMENT '产品ID - 系统主键',
  `product_name` varchar(128) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '产品名称 - 后台展示名称',
  `state` int(11) NOT NULL COMMENT '状态',
  `currency` varchar(16) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '币种 - 借款币种',
  `min_loan_amount` decimal(18,2) NOT NULL DEFAULT '0.00' COMMENT '最低借款金额',
  `max_loan_amount` decimal(18,2) DEFAULT NULL COMMENT '最高借款金额',
  `amount_step` decimal(18,2) DEFAULT NULL COMMENT '金额步长, 借款金额递增单位',
  `min_term` int(11) NOT NULL COMMENT '最小分期期数, 最少可选期数',
  `max_term` int(11) DEFAULT NULL COMMENT '最大分期期数，最多可选期数',
  `default_term` int(11) DEFAULT NULL COMMENT '默认分期期数，用户默认看到的期数',
  `period_days` int(11) NOT NULL COMMENT '每期天数',
  `max_days` int(11) DEFAULT NULL COMMENT '借款最大总天数',
  `daily_interest_rate` decimal(10,6) NOT NULL COMMENT '日利率，每日利息费率',
  `daily_service_fee_rate` decimal(10,6) NOT NULL DEFAULT '0.000000' COMMENT '日服务费率',
  `overdue_rate` decimal(10,6) NOT NULL DEFAULT '0.000000' COMMENT '日逾期费率',
  `cooling_off_hours` int(11) NOT NULL DEFAULT '0' COMMENT '冷静期小时数',
  `cooling_off_fee_free` tinyint(1) DEFAULT NULL COMMENT '冷静期免息费，冷静期内是否免利息和服务费',
  `enable_early_repay` tinyint(1) DEFAULT NULL COMMENT '支持当期提前还款，是否允许未到期账单提前还款',
  `early_repay_open_days` int(11) DEFAULT NULL COMMENT '提前还款开放天数，到期日前几天开放入口',
  `enable_early_settlement` tinyint(1) DEFAULT NULL COMMENT '支持提前结清，是否允许一次性结清所有未还账单',
  `enable_partial_repay` tinyint(1) DEFAULT NULL COMMENT '支持部分还款，是否允许有多少钱还多少钱',
  `min_partial_repay_amount` decimal(18,2) DEFAULT NULL COMMENT '最低部分还款金额，单次部分还款最低金额',
  `max_overdue_days` int(11) DEFAULT NULL COMMENT '最大逾期天数，期费最多计算多少天',
  `max_overdue_fee_cap_rate` decimal(18,6) DEFAULT NULL COMMENT '逾期费封顶比例，逾期费相对本金的封顶比例',
  `repay_allocation_rule` json DEFAULT NULL COMMENT '还款冲抵规则，部分还款时先冲什么',
  `rounding_type` varchar(32) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '取整规则类型，金额展示和收取取整方式',
  `user_tag` varchar(32) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '适用用户类型，产品适合哪些用户',
  `risk_level` varchar(32) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '风险等级，产品适用风险等级',
  `sort_no` int(11) NOT NULL DEFAULT '0' COMMENT '排序号，前端展示排序',
  `remark` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '备注',
  `is_del` bigint(20) NOT NULL DEFAULT '0' COMMENT '删除标识 - 0:未删除 1:已删除',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间 - 记录创建时间',
  `modify_time` datetime DEFAULT NULL COMMENT '更新时间 - 记录更新时间'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='借贷产品表';;

CREATE TABLE `loan_repayment_bill` (
  `id` bigint(20) NOT NULL COMMENT '主键',
  `voucher_no` varchar(64) NOT NULL COMMENT '借款订单号',
  `bill_no` varchar(64) NOT NULL COMMENT '分期账单号',
  `user_id` bigint(20) NOT NULL COMMENT '客户ID',
  `term_seq` int(11) DEFAULT NULL COMMENT '期数',
  `state` int(11) DEFAULT NULL COMMENT '状态',
  `original_bill_amount` decimal(18,2) DEFAULT NULL COMMENT '本期初始应还金额 - 生成还款订单时，该账单应还金额',
  `bill_remaining_amount` decimal(18,2) DEFAULT NULL COMMENT '账单剩余金额快照 - 生成还款订单时，该账单剩余待还',
  `coupon_amount` decimal(18,2) DEFAULT NULL COMMENT '本次还款优惠券分摊到这个账单的金额',
  `payable_amount` decimal(18,2) DEFAULT NULL COMMENT '本次应付金额, bill_remaining_amount - coupon_amount',
  `allocated_amount` decimal(18,2) DEFAULT NULL COMMENT '实际分配金额, 支付成功后实际分配到这个账单的金额',
  `difference_amount` decimal(18,2) DEFAULT NULL COMMENT '差额金额, payable_amount - allocated_amount',
  `paid_time` datetime DEFAULT NULL COMMENT '支付成功时间, 这个账单在本还款订单中完成的时间',
  `is_del` bigint(20) NOT NULL DEFAULT '0' COMMENT '是否删除, 0:否，其他：删除时间戳',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `modify_time` datetime DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`),
  KEY `idx_repayment_bill_voucher_no` (`voucher_no`) USING BTREE,
  KEY `idx_repayment_bill_voucher_bill_no` (`bill_no`) USING BTREE,
  KEY `idx_repayment_bill_user_id` (`user_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='还款订单明细';;

CREATE TABLE `loan_disbursement_record` (
  `id` bigint(20) NOT NULL COMMENT '主键',
  `disbursement_no` varchar(64) DEFAULT NULL COMMENT '放款单号',
  `apply_no` varchar(64) NOT NULL COMMENT '申请单号',
  `user_id` bigint(20) NOT NULL COMMENT '客户ID',
  `product_id` bigint(20) NOT NULL COMMENT '产品ID - 产品ID',
  `apply_amount` decimal(18,2) DEFAULT NULL COMMENT 'applyAmount',
  `disbursed_amount` decimal(18,2) DEFAULT NULL COMMENT '实际放款金额',
  `disbursement_channel` varchar(32) DEFAULT NULL COMMENT '放款渠道 - Easypaisa/JazzCash/Bank/Manual',
  `payment_account_id` bigint(20) DEFAULT NULL COMMENT '收款账户id',
  `channel_txn_no` varchar(128) DEFAULT NULL COMMENT '渠道交易号，三方放款流水',
  `state` int(11) NOT NULL COMMENT '放款状态 - Pending/Success/Failed/Cancelled',
  `fail_reason` varchar(255) DEFAULT NULL COMMENT '失败原因 - 放款失败原因',
  `request_time` datetime DEFAULT NULL COMMENT '发起时间，放款发起时间',
  `success_time` datetime DEFAULT NULL COMMENT '成功时间，放款成功时间',
  `callback_time` datetime DEFAULT NULL COMMENT '回调时间，渠道回调时间',
  `raw_payload` text COMMENT '原始报文 - 渠道原始返回',
  `is_del` bigint(20) NOT NULL DEFAULT '0' COMMENT '是否删除, 0:否，其他：删除时间戳',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `modify_time` datetime DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `idx_disbursement_record_no` (`disbursement_no`) USING BTREE,
  KEY `idx_disbursement_apply_no` (`apply_no`) USING BTREE,
  KEY `idx_disbursement_user_id` (`user_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='放款记录表';;

CREATE TABLE `loan_coupon_instance` (
  `id` bigint(20) NOT NULL COMMENT '主键ID',
  `coupon_no` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '优惠券编号',
  `template_id` bigint(20) NOT NULL COMMENT '优惠券模板id',
  `coupon_name` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '优惠券名称',
  `coupon_type` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '优惠券类型',
  `user_id` bigint(20) NOT NULL COMMENT '客户ID',
  `coupon_amount` decimal(18,2) NOT NULL DEFAULT '0.00' COMMENT '优惠券金额',
  `product_id` bigint(20) DEFAULT NULL COMMENT '适用产品ID',
  `state` int(11) NOT NULL COMMENT '状态',
  `effect_time` datetime NOT NULL COMMENT '生效开始时间',
  `expire_time` datetime DEFAULT NULL COMMENT '过期时间',
  `biz_no` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '锁定业务单号',
  `locked_time` datetime DEFAULT NULL COMMENT '锁定时间',
  `used_time` datetime DEFAULT NULL COMMENT '使用时间',
  `is_del` bigint(20) NOT NULL DEFAULT '0' COMMENT '删除标识 - 0:未删除 1:已删除',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `modify_time` datetime DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `idx_coupon_instance_coupon_no` (`coupon_no`) USING BTREE,
  KEY `idx_coupon_instance_template_id` (`template_id`) USING BTREE,
  KEY `idx_coupon_instance_user_id` (`user_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='优惠券';;

SET FOREIGN_KEY_CHECKS = 1;
